"""Flask REST API for text transformations.

A single-file runnable implementation of the /api/transform endpoint.
"""

from flask import Flask, request, jsonify
from typing import Any

app = Flask(__name__)


@app.route("/api/transform", methods=["POST"])
def transform() -> tuple[Any, int]:
    """Handle POST /api/transform requests to perform text transformations.

    Accepts a JSON body with 'text' (string) and 'operation' (one of:
    'uppercase', 'reverse', 'count_words').

    Returns:
        - 200 with {"result": ..., "operation": ..., "original_length": ...} for valid input.
        - 400 with {"error": "..."} for invalid JSON, missing/invalid fields,
          or unsupported operations.

    All responses include Content-Type: application/json.
    """
    data: Any = request.get_json(silent=True)

    if data is None or not isinstance(data, dict):
        return (
            jsonify({"error": "Request body must be valid JSON"}),
            400,
        )

    text: Any = data.get("text")
    if text is None or not isinstance(text, str):
        return (
            jsonify({"error": "The 'text' field is required and must be a string"}),
            400,
        )

    operation: Any = data.get("operation")
    if operation is None or not isinstance(operation, str):
        return (
            jsonify({"error": "The 'operation' field is required and must be a string"}),
            400,
        )

    if operation not in {"uppercase", "reverse", "count_words"}:
        return (
            jsonify(
                {
                    "error": (
                        f"Unsupported operation '{operation}'. "
                        "Supported operations are: uppercase, reverse, count_words"
                    )
                }
            ),
            400,
        )

    original_length: int = len(text)

    if operation == "uppercase":
        result: str | int = text.upper()
    elif operation == "reverse":
        result = text[::-1]
    else:  # count_words
        result = len(text.split())

    return (
        jsonify(
            {
                "result": result,
                "operation": operation,
                "original_length": original_length,
            }
        ),
        200,
    )


if __name__ == "__main__":
    app.run(debug=True, port=5000)
```

